MAP
#
#< Start of map file - created 2011-05-07 - 21:21:20
#
NAME 'CATBR_VERTICES'
STATUS ON

PROJECTION
			'init=epsg:32720'     # UTM 20, Zona 20S, WGS 1984
END

SIZE 1200 1200
EXTENT 700000 8225000 730000 8255000
UNITS  meters
SYMBOLSET 'c:/apache2/cat_br/mapa/symbols/symbset.sym'
FONTSET   'c:/apache2/cat_br/mapa/fonts/fonts.fnt'
IMAGECOLOR 244 255 228

#
# Start of web interface definition
#
WEB
 LOG catbr_vertices.log
 TEMPLATE catbr_vertices.html
 IMAGEPATH 'c:/apache2/htdocs/tmp/'
 IMAGEURL 'http://localhost/tmp/'
 EMPTY 'http://localhost/catastro_br/nada.html'
 
 METADATA
  WMS_ONLINERESOURCE 'http://localhost/cgi-bin/mapserv.exe?map=c:/apache2/cat_br/mapa/catbr_vertices.map'
  WMS_SRS 'epsg:32720'
  WMS_ACCESSCONSTRAINTS 'none'
  WMS_TITLE 'CATBR_VERTICES'
  WMS_FEATURE_INFO_MIME_TYPE 'text/html'
  WMS_ABSTRACT ''
 END  #METADATA

END  #HEADER

OUTPUTFORMAT
  NAME 'png'
	DRIVER 'GDAL/PNG'
	MIMETYPE 'image/png'
	IMAGEMODE RGB
	EXTENSION 'png'
	FORMATOPTION 'QUALITY=100'
END

SYMBOL
   NAME 'circle'
   TYPE ellipse
   FILLED true
   POINTS
     1 1
   END
END

#
# Start of reference map
#
REFERENCE
  STATUS OFF
  IMAGE 'c:/apache2/htdocs/catastro_br/data/reference.gif'
  SIZE 120 120
  EXTENT -70.254 -23.569 -56.844 -8.994
  COLOR -1 -1 -1
  OUTLINECOLOR 255 0 0
END  #REFERENCE

#
# Start of legend
#
LEGEND
  STATUS OFF
  KEYSIZE 16 8
  TEMPLATE 'legend.html'
  LABEL
    COLOR 120 120 120
  END # ENDE LABEL
END   #LEGEND

#
# Start of scalebar
#
SCALEBAR
 STATUS OFF
 POSITION ll
 STYLE 0
 INTERVALS 5
 IMAGECOLOR 255 255 255
 LABEL
  COLOR 0 0 0
  SIZE GIANT  #SMALL
 END  #ENDE LABEL
 #SIZE 150 2
 #SIZE 304 4   #Mapsize 700+700
 Size 600 8    #Mapsize 1400+1400
 TRANSPARENT OFF
 COLOR 0 0 0
 BACKGROUNDCOLOR 255 255 255
 OUTLINECOLOR 100 100 100
 UNITS METERS
END   #SCALEBAR

#
# Start of layer definitions #
#
#----------------------------------------------------------- Colindantes
LAYER
  CONNECTIONTYPE postgis 
  NAME 'colindante'
	GROUP 'Predio'
	STATUS ON
	CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_poly USING UNIQUE oid'
  TYPE LINE
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'colindante'
 WMS_GROUP_TITLE 'Predio'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

 CLASSITEM 'number'
	CLASS 
    NAME 'Predio'
		EXPRESSION (( '[number]' == '5' ) AND ('[user_id]' == 'AAA' ))               
		STYLE
		  SYMBOL 'linea'
      COLOR 200 200 200
	    SIZE 2
	  END
	END # end_of_class	
	

END # end of layer object
#----------------------------------------------------------- Colindantes
#----------------------------------------------------------- Predio-Poligono
LAYER
  CONNECTIONTYPE postgis 
  NAME 'predio'
	GROUP 'Predio'
	STATUS ON
	CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_poly USING UNIQUE oid'
  TYPE POLYGON
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'predio'
 WMS_GROUP_TITLE 'Predio'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

 CLASSITEM 'number'	
	CLASS 
    NAME 'Predio'
		EXPRESSION (( '[number]' == '2' ) AND ('[user_id]' == 'AAA' ))               
		STYLE
		  SYMBOL 'circle'
      COLOR -1 -1 -1
			OUTLINECOLOR 255 0 0		
	    SIZE 2
	  END
	END # end_of_class
	CLASS 
    NAME 'Predio'
		EXPRESSION (( '[number]' == '10' ) AND ('[user_id]' == 'AAA' ))               
  	STYLE
	 	  SYMBOL 'circle'
       COLOR -1 -1 -1
	  	 OUTLINECOLOR 0 0 255			
	     SIZE 2
	  END
	END # end_of_class	

END # end of layer object
#----------------------------------------------------------- Predio-Poligono
#----------------------------------------------------------- Predio-Anotation
LAYER  # START OF ANNOTATION LAYERFILE
  CONNECTIONTYPE postgis
  NAME 'predio_anot'
	GROUP 'Predio'
  CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_poly USING UNIQUE oid'
  STATUS ON
  TYPE ANNOTATION
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'points_anot'
 WMS_GROUP_TITLE 'Puntos'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END

PROJECTION
     	'init=epsg:32720'
END

  CLASSITEM 'number'
  LABELITEM 'cod_cat'
 
    CLASS
     NAME 'Codigo Predio'
     EXPRESSION (( '[number]' == '2' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 14
       ANGLE 0
       COLOR 255 0 0
       BUFFER 10
			 OFFSET 0 0
       POSITION cc
       PARTIALS FALSE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS
    CLASS
     NAME 'Codigo Colindantes'
     EXPRESSION (( '[number]' == '5' ) AND ('[user_id]' == 'AAA' ) AND ('[cod_cat]' != '01-05-001' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 200 200 200
       BUFFER 5
			 OFFSET 0 0
       POSITION cc
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS		
		 
END  # END OF LAYERFILE
#----------------------------------------------------------- Predio-Anotation
#----------------------------------------------------------- Radio_Ochaves
