 WMS_TITLE 'Radio_Ochaves'
 WMS_GROUP_TITLE 'Puntos'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
#      	'init=epsg:4326'
END	

CLASSITEM 'id'
	
    CLASS
     NAME 'Calle'
      EXPRESSION (( '[id]' == '0' ) AND ('[user_id]' == 'AAA' ))
		 STYLE
		   SYMBOL 'gestrichelt2'
       COLOR 0 0 255
	     SIZE 1
	   END
