#----------------------------------------------------------- Radio_Ochaves-Anotacion
LAYER
  CONNECTIONTYPE postgis 
  NAME 'Calles_Anot'
	GROUP 'Puntos'
	STATUS ON
	CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_line USING UNIQUE oid'
  TYPE ANNOTATION
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'calles_anot'
 WMS_GROUP_TITLE 'Puntos'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END
	
PROJECTION
     	'init=epsg:32720'
END	

CLASSITEM 'id'
LABELITEM 'tipo'
	
    CLASS
     NAME 'Nombre'
     EXPRESSION (( '[id]' == '0' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 7
       ANGLE AUTO
       COLOR 0 0 255
			 #OUTLINECOLOR 255 0 0
       BUFFER 3
			 OFFSET 0 0
       POSITION uc
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS
END # end of layer object
#----------------------------------------------------------- Radio_Ochaves_Anotacion
#----------------------------------------------------------- Points
LAYER
  CONNECTIONTYPE postgis
  NAME 'points'
	GROUP 'Puntos'
  CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_point USING UNIQUE oid'
  STATUS ON
  TYPE POINT
	
	METADATA
  WMS_SRS 'epsg:32720'
  WMS_TITLE 'POINTS'
	WMS_GROUP_TITLE 'Puntos'
  WMS_FEATURE_INFO_MIME_TYPE 'text/html'
  END

 PROJECTION
      	'init=epsg:32720'
 END
   #SYMBOLSCALE 1000
	 CLASSITEM 'pos'
   TRANSPARENCY 1000
	  
		CLASS
      NAME 'Centroid'
      EXPRESSION (( '[pos]' == 'CEN' ) OR ('[pos]' == 'NN' ))
      STYLE
        SYMBOL 'circle'
				COLOR -1 -1 -1
				SIZE 0
      END
    END  # END_OF_CLASS	
		CLASS
      NAME 'TEXT'
      EXPRESSION ((( '[pos]' == 'NO' )OR('[pos]' == 'NE' )OR( '[pos]' == 'SO' )OR('[pos]' == 'SE' )OR('[pos]' == '--' )) AND ('[user_id]' == 'AAA' )) 
      STYLE
         SYMBOL 'vertice'
				SIZE 3
      END
    END  # END_OF_CLASS


END   # END OF LAYERFILE
#----------------------------------------------------------- Points
#----------------------------------------------------------- Points-Anotation
LAYER  # START OF ANNOTATION LAYERFILE
  CONNECTIONTYPE postgis
  NAME 'points_anot'
	GROUP 'Puntos'
  CONNECTION 'user=postgres password=qwert dbname=cat_buenretiro host=localhost'
  DATA 'the_geom from temp_point USING UNIQUE oid'
  STATUS ON
  TYPE ANNOTATION
METADATA
 WMS_SRS 'epsg:32720'
 WMS_TITLE 'points_anot'
 WMS_GROUP_TITLE 'Puntos'
 WMS_FEATURE_INFO_MIME_TYPE 'text/html'
END

PROJECTION
     	'init=epsg:32720'
END

  CLASSITEM 'pos'
  LABELITEM 'text'
 
    CLASS
     NAME 'SO'
     EXPRESSION (( '[pos]' == 'SO' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 0
       BUFFER 3
			 OFFSET 5 5
       POSITION ll
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS
		CLASS
     NAME 'NO'
     EXPRESSION (( '[pos]' == 'NO' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 0
       BUFFER 3
			 OFFSET 5 5
       POSITION ul
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS
		CLASS
     NAME 'SE'
     EXPRESSION (( '[pos]' == 'SE' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 0
       BUFFER 3
			 OFFSET 5 5
       POSITION lr
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS
		CLASS
     NAME 'NE'
     EXPRESSION (( '[pos]' == 'NE' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 0
       BUFFER 3
			 OFFSET 5 5
       POSITION ur
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS
		CLASS
    NAME 'INTERMEDIOS'
     EXPRESSION (( '[pos]' == '--' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 255
       BUFFER 3
			 OFFSET 10 10
       POSITION cc
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
    END  # CLASS		 
		CLASS
    NAME 'CEN'
     EXPRESSION (( '[pos]' == 'CEN' ) AND ('[user_id]' == 'AAA' ))
      LABEL
       TYPE TRUETYPE
       FONT tahoma
       SIZE 10
       ANGLE 0
       COLOR 0 0 255
       BUFFER 3
			 OFFSET 0 0
       POSITION cc
       PARTIALS TRUE
			 FORCE TRUE
			 ANTIALIAS TRUE
      END
     END  # CLASS
				 
END  # END OF LAYERFILE
