#----------------------------------------------------------- Flecha Norte
LAYER
    NAME 'n_arrow'
    STATUS ON
		GROUP 'Predio'
    TRANSFORM FALSE
    TYPE POINT
		METADATA
      WMS_TITLE 'North Arrow'
			WMS_GROUP_TITLE 'North Arrow'
      WMS_FEATURE_INFO_MIME_TYPE 'text/html'
    END
		
    TRANSPARENCY 1000		
    
		FEATURE
      POINTS 360 30 END
    END
    CLASS
      STYLE
        SYMBOL 'n_arrow_med'	
      END
    END
END
#----------------------------------------------------------- Flecha Norte
